#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="C:\Users\48796\Documents\AXELREPS\node_modules\.pnpm\h3@2.0.1-rc.23_crossws@0.4.9_srvx@0.11.21_\node_modules\h3\node_modules;C:\Users\48796\Documents\AXELREPS\node_modules\.pnpm\h3@2.0.1-rc.23_crossws@0.4.9_srvx@0.11.21_\node_modules;C:\Users\48796\Documents\AXELREPS\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/c/Users/48796/Documents/AXELREPS/node_modules/.pnpm/h3@2.0.1-rc.23_crossws@0.4.9_srvx@0.11.21_/node_modules/h3/node_modules:/mnt/c/Users/48796/Documents/AXELREPS/node_modules/.pnpm/h3@2.0.1-rc.23_crossws@0.4.9_srvx@0.11.21_/node_modules:/mnt/c/Users/48796/Documents/AXELREPS/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../h3/bin/h3.mjs" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../h3/bin/h3.mjs" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../h3/bin/h3.mjs" $args
  } else {
    & "node$exe"  "$basedir/../h3/bin/h3.mjs" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
